INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optometrist-moex-03444', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一病患的屈光度數為-5.00 DS，沒有散光，若使用視網膜檢影鏡檢查此病患，請問下列何者錯誤？', '["檢查者於檢查距離30公分，觀察到的是逆動（against motion）現象", "檢查者於檢查距離10公分，觀察到的是順動（with motion）現象", "檢查者於檢查距離20公分，觀察到的是中和現象（neutrality）", "檢查者於檢查距離50公分，在病患眼前放置-2.0 D的凹透鏡，可觀察到中和現象（neutrality）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03445', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列有關兩眼不等視（anisometropia）的敘述何者錯誤？', '["兩眼不等視會造成投射在視網膜上的成像大小不等，稱為不等像（aniseikonia）", "一般人可忍受的像差大約是5%，不等像嚴重會產生調節性眼睛疲勞（accommodative asthenopia）的症狀", "兩眼屈光不正，性質互異，一眼有利看近，一眼有利看遠，視力使用上會發生輪流交替現象，有時會 伴有眼肌不平衡（斜視）的發生", "框架眼鏡對不等視的矯正，可減少稜鏡效應，較隱形眼鏡有利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03446', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '某一患者的屈光度數為-1.00 DS/-1.00 DC × 180°，請問這患者的最小模糊圈（the circle of least confusion） 所在位置的屈光度數為？', '["-1.00 DS", "-1.50 DS", "-2.00 DS", "-2.50 DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03447', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '調節性內斜視（accommodative esotropia）最常發生在有下列何項屈光狀態的患者？', '["高度近視", "正視眼", "散光", "高度遠視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03448', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一個5歲的小孩，右眼屈光度數為+5.00 DS，最佳矯正視力為0.05，左眼屈光度數為+0.25 DS，最佳矯正 視力為1.0；請問此小孩的弱視病因診斷，最可能是下列何者？', '["不等視性弱視（anisometropic amblyopia）", "剝奪性弱視（deprivational amblyopia）", "斜視性弱視（strabismic amblyopia）", "非正視性弱視（isoametropic amblyopia）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03449', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '馬竇氏鏡（Maddox rod）放置於受檢者的右眼，柱面透鏡放置方向為水平，會看到垂直的線，評估水平隱 斜位。下列選項何者正確？', '["線在光點的右邊，有未矯正的內斜。應使用基底在內的稜鏡矯正眼位", "線在光點的右邊，有未矯正的外斜。應使用基底在內的稜鏡矯正眼位", "線在光點的右邊，有未矯正的內斜。應使用基底在外的稜鏡矯正眼位", "線在光點的右邊，有未矯正的外斜。應使用基底在外的稜鏡矯正眼位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03450', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '某正視眼（emmetropia）患者，看遠時是正眼位（orthophoria），若此病患的調節性內聚力/調節力的比值 （accommodative convergence/accommodation ratio, AC/A ratio）為1，請問此病患看近時，最有可能的眼 位為下列何者？', '["上斜位", "下斜位", "內斜位", "外斜位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03451', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '戴上矯正鏡片後，看近距離40公分處有6稜鏡度（Δ）的外斜位（exophoria），再加上-1.00 D的球面鏡 後可矯正成正眼位（orthophoria），以斜度法（gradient method）計算調節性內聚力與調節力的比值（AC/A ratio）為：', '["6", "5", "4", "3"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03452', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '眼位檢查發現看遠方6公尺處有2稜鏡度（Δ）的外斜位（exophoria），看40公分處有10稜鏡度（Δ） 的外斜位（exophoria）。最可能的情形為：', '["內聚力不足（convergence insufficiency）", "內聚力過度（convergence excess）", "開散力不足（divergence insufficiency）", "開散力過度（divergence excess）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03453', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '受檢者有遠視+2.50 DS，接受近視力檢查。逐漸以0.25 D降低看遠用的凸透鏡度數到平光時，受檢者無 法再看清楚視標，檢查結果是：', '["實性相關調節力（positive relative accommodation）為+2.50 D", "虛性相關調節力（negative relative accommodation）為+2.50 D", "實性相關調節力（positive relative accommodation）為-2.50 D", "虛性相關調節力（negative relative accommodation）為-2.50 D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "b04495330ac2", "answer_pdf_sha1": "a8ea1edd93f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
